 55	export const createRunCallbackTracker = (): RunCallbackTracker => {
 56	  const entities = new Map<string, MutableCallbackReference>();
 57	  const quests = new Map<string, MutableCallbackReference>();
 58	
 59	  const recordEvent = (event: CallbackRunEvent): void => {
 60	    const data = asRecord(event.data);
 61	    if (data === null) {
 62	      return;
 63	    }
 64	
 65	    const turn = event.turn ?? 0;
 66	    for (const entityId of entityIdsFromData(data)) {
 67	      upsertReference(entities, "entity", entityId, event.type, turn);
 68	    }
 69	    for (const questId of questIdsFromData(data)) {
 70	      upsertReference(quests, "quest", questId, event.type, turn);
 71	    }
 72	  };
 73	
 74	  return {
 75	    recordEvent,
 76	    recordEvents: (events) => {
 77	      for (const event of events) {
 78	        recordEvent(event);
 79	      }
 80	    },
 81	    snapshot: () => ({
 82	      entities: freezeReferences(entities),
 83	      quests: freezeReferences(quests),
 84	    }),
 85	  };
 86	};
