 88	export const renderRunCallbackBlock = (
 89	  snapshot: RunCallbackSnapshot,
 90	  options: RunCallbackRenderOptions = {},
 91	): string => {
 92	  const maxReferences =
 93	    options.maxReferencesPerKind ?? DEFAULT_REFERENCES_PER_KIND;
 94	  const tokenBudget = options.tokenBudget ?? DEFAULT_CALLBACK_TOKEN_BUDGET;
 95	  const lines = [CALLBACK_HEADER];
 96	  appendReferenceLines(lines, snapshot.quests, maxReferences, tokenBudget);
 97	  appendReferenceLines(lines, snapshot.entities, maxReferences, tokenBudget);
 98	  return lines.length === 1 ? "" : lines.join("\n");
 99	};
