101	export const buildLearnedSummary = (
102	  runSummary: RunSummary,
103	  events: readonly CallbackRunEvent[],
104	): string => {
105	  const runFacts = runFactsFromSummary(runSummary);
106	  const tracker = createRunCallbackTracker();
107	  tracker.recordEvents(events);
108	  const snapshot = tracker.snapshot();
109	  const deathCount = events.filter(isPlayerDeathEvent).length;
110	  const refusedQuestIds = eventIdsByType(events, "quest_refused", "questId");
111	  const completedQuestIds = eventIdsByType(events, "quest_completed", "questId");
112	  const failedQuestIds = eventIdsByType(events, "quest_failed", "questId");
113	  const hoardNames = eventIdsByType(events, "hoard_taken", "name");
114	
115	  const clauses = [runFacts];
116	  if (deathCount > 0) {
117	    clauses.push("the delver died");
118	  }
119	  if (refusedQuestIds.length > 0) {
120	    clauses.push(`refused ${joinReadable(refusedQuestIds)}`);
121	  }
122	  if (completedQuestIds.length > 0) {
123	    clauses.push(`completed ${joinReadable(completedQuestIds)}`);
124	  }
125	  if (failedQuestIds.length > 0) {
126	    clauses.push(`failed ${joinReadable(failedQuestIds)}`);
127	  }
128	  if (hoardNames.length > 0) {
129	    clauses.push(`reached the Hoard for ${joinReadable(hoardNames)}`);
130	  }
131	  if (snapshot.entities.length > 0) {
132	    clauses.push(
133	      `callbacks should remember ${joinReadable(
134	        snapshot.entities.slice(0, 3).map((entity) => entity.id),
135	      )}`,
136	    );
137	  }
138	
139	  return `What the dungeon learned: ${clauses.join("; ")}.`;
140	};
