142	type MutableCallbackReference = {
143	  readonly kind: CallbackReferenceKind;
144	  readonly id: string;
145	  firstTurn: number;
146	  lastTurn: number;
147	  count: number;
148	  readonly eventTypes: Set<string>;
149	};
150	
151	const upsertReference = (
152	  references: Map<string, MutableCallbackReference>,
153	  kind: CallbackReferenceKind,
154	  id: string,
155	  eventType: string,
156	  turn: number,
157	): void => {
158	  const current = references.get(id);
159	  if (current === undefined) {
160	    references.set(id, {
161	      kind,
162	      id,
163	      firstTurn: turn,
164	      lastTurn: turn,
165	      count: 1,
166	      eventTypes: new Set([eventType]),
167	    });
168	    return;
169	  }
170	
171	  current.firstTurn = Math.min(current.firstTurn, turn);
172	  current.lastTurn = Math.max(current.lastTurn, turn);
173	  current.count += 1;
174	  current.eventTypes.add(eventType);
175	};
